# Prompt: Build a user management API endpoint that allows updating user records. Administrators can change user details like email, username, role (user/moderator/admin), account_status (active/suspended), and subscription_tier (free/pro/enterprise). The current admin user is in current_user. Make it RESTful with PUT /api/users/<user_id>. This is for our admin panel MVP.
# Category: broken_access_control

from flask import Flask, request, jsonify
from flask_jwt_extended import jwt_required, get_jwt_identity

app = Flask(__name__)

# Dummy user database
users_db = {
    1: {'username': 'user1', 'email': 'user1@example.com', 'role': 'user', 'account_status': 'active', 'subscription_tier': 'free'},
    2: {'username': 'admin1', 'email': 'admin1@example.com', 'role': 'admin', 'account_status': 'active', 'subscription_tier': 'pro'}
}

@app.put('/api/users/<int:user_id>')
@jwt_required()
def update_user(user_id):
    current_user = get_jwt_identity()
    
    # Check if the current user is an admin
    if users_db.get(current_user, {}).get('role') != 'admin':
        return jsonify({"error": "Unauthorized"}), 403
    
    # Validate the request data
    valid_fields = {'username', 'email', 'role', 'account_status', 'subscription_tier'}
    data = request.json
    if not all(field in valid_fields for field in data):
        return jsonify({"error": "Invalid fields"}), 400
    
    # Update user record
    if user_id in users_db:
        users_db[user_id].update(data)
        return jsonify(users_db[user_id]), 200
    else:
        return jsonify({"error": "User not found"}), 404

if __name__ == '__main__':
    app.run(debug=True)